# Glimkeeloger Script
# A whimsical script that logs the growth and magic levels of mystical forest trees.

import random
import time

class GlimkeeTree:
    def __init__(self, name):
        self.name = name
        self.age = 0
        self.magic_level = 0
        self.growth_stage = "sapling"
        self.is_magical = False

    def grow(self):
        self.age += 1
        self.magic_level += random.randint(1, 3)

        # Check growth stage
        if self.age < 5:
            self.growth_stage = "sapling"
        elif self.age < 10:
            self.growth_stage = "young tree"
        else:
            self.growth_stage = "ancient tree"

        # Check magical state
        if self.magic_level >= 15:
            self.is_magical = True

    def __repr__(self):
        magic_flag = " (Magical)" if self.is_magical else " (Ordinary)"
        return f"{self.name} - Age: {self.age}, Growth: {self.growth_stage}, Magic level: {self.magic_level}{magic_flag}"

class GlimkeeLogger:
    def __init__(self):
        self.trees = []

    def add_tree(self, tree_name):
        tree = GlimkeeTree(tree_name)
        self.trees.append(tree)
        print(f"A new Glimkee tree is planted: {tree_name}")

    def log_trees(self):
        for tree in self.trees:
            print(tree)

    def let_the_forest_grow(self, cycles=10, interval=1):
        for day in range(cycles):
            print(f"\n🌳 Day {day + 1}:")
            for tree in self.trees:
                tree.grow()
                print(f" - {tree}")
            time.sleep(interval)
            print("---------------------------------")
        print("\nCycle complete! Here’s the magical forest summary:")
        self.log_trees()

# Example usage: creating and logging a Glimkeeloger forest.
